1	const BASE_PRICE_BY_TYPE: Record<string, number> = {
2	  potion: 40,
3	  amulet: 60,
4	  staff: 80,
5	  sword: 100,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	const RUNE_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const RUNE_COMPONENT_BLOCK_SIZE = 3;
11	const RUNE_COMPONENT_BLOCK_PRICE = 60;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	
17	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
18	const PROCESSING_FEE = 5;
19	
20	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[] }): number {
21	  const items = input.items;
22	  const countByType: Record<string, number> = {};
23	  for (const item of items) {
24	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
25	  }
26	  let basePrice = 0;
27	  for (const type of Object.keys(countByType)) {
28	    const count = countByType[type];
29	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
30	    if (formsRuneBlock) {
31	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
32	    } else {
33	      basePrice += count * BASE_PRICE_BY_TYPE[type];
34	    }
35	  }
36	  let highEnchantmentSurcharges = 0;
37	  let cursedSurcharges = 0;
38	  for (const item of items) {
39	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
40	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
41	    }
42	    if (item.cursed === true) {
43	      cursedSurcharges += BASE_PRICE_BY_TYPE[item.type] * CURSE_SURCHARGE_RATE;
44	    }
45	  }
46	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
47	  const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? basePrice * 0.2 : 0;
48	  const premium = basePrice + cursedSurcharges + highEnchantmentSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE;
49	  return Math.ceil(premium);
50	}
